INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6e2f88c7-moex-00206', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '甲住處附近設有多台扭蛋機，甲對其中的公仔、模型、玩具都很喜愛，
但因為扭蛋機扭一次需費100元，自己阮囊羞澀，所以無法常常去消費。
某日，甲突發奇想，以鐵絲穿進扭蛋機投幣口觸動內部開關，不花分文
扭出 1顆扭蛋後揚長而去。試問甲觸犯刑法上何罪名？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "99a924c77d18", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00207', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '不同黑社會幫派的甲跟乙因為爭地盤結下梁子，兩人皆時常對外放話要
找機會向對方尋仇。一日，甲在街上看見乙，便潛行至乙的背後，拿出
隨身攜帶的西瓜刀對乙的右腳腳踝砍去，意在使乙右腳殘廢，乙右腳遭
砍之後倒臥在地，殊不知乙係奉幫派老大之命欲暗殺 A，此時正持槍瞄
準 A，在扣扳機之際卻遭甲刀砍而暗殺失敗，A因此免於喪命。乙經送
醫急救後，右腳腳踝截肢，終身殘廢。試問甲有何刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "99a924c77d18", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00208', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '甲與 A結怨已久，常思要好好教訓 A。甲偶然間結識黑道混混乙，遂以
10 萬元為報酬指使乙教訓一下 A，讓 A吃點皮肉之苦。乙收錢後翌日便
持棍棒埋伏在 A家外面，計畫待A返家時教訓 A。不久後，乙見一人來
到 A家門口，乙便持棍棒衝上前去亂棒毆打，打完後方發現自己粗心地
打錯人，被打的是與 A體型完全不同的鄰居 B，全身多處紅腫挫傷的 B
嗣後提出相關告訴。試問甲、乙有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "99a924c77d18", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00209', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', 'A股份有限公司（下稱 A公司）為上市公司，其董事會為增加 A公司對
股東分配的彈性，除期末年度分派之外，也欲於每季為盈餘分派，請說
明依公司法規定，A 公司應完成之相關程序及決策機關為何？又嗣後 A
公司如在採用每季盈餘分派方式時，董事會因過度樂觀預估年度中 A公
司有獲利並進行期中分派，但於期末決算時，A 公司實際卻是虧損，已
接受期中分派之股東是否有補償A公司之義務？（40分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "2964ccdcbdb9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0808", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00210', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '甲簽發以 A銀行為付款人，面額新臺幣（下同）參仟元之支票交付於乙，
乙將支票面額變造為參萬元給不知情之丙以抵付貨款，丙又將支票背書
轉讓給不知情之丁，屆期丁持支票向 A銀行如數兌現。嗣後甲發現該支
票係經乙變造，遂向丁主張返還不當得利，請求丁返還貳萬柒仟元之差
額，問：甲之主張是否有理由？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "2964ccdcbdb9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0808", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00211', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', 'A 航運公司將其所有之船舶甲輪租給 B 海運公司（下稱 B 公司），雙方
並訂立光船租賃契約，而在承租期間，因 B公司僱用之船員航行不慎，
在進入臺北港時，造成碼頭之碰撞與毀損，問：B 公司得否主張海商法
第 21 條船舶所有人責任限制？又在甲輪離開臺北港時，甲輪發生故障，
船上重燃油外洩，污染附近海域，對此污染造成的損害，B 公司得否主
張海商法第 21條船舶所有人責任限制？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "2964ccdcbdb9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0808", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00212', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '甲新購買大型重機時，同時與 A保險公司之業務員乙詢問機車車損保險
之事宜，甲乙雙方就保險契約之內容表示意思一致，A保險公司並接受
甲之要約，甲隨後騎著新購置大型重機，前往 A保險公司指定處所繳交
保險費。不料，甲在繳交保費途中發生車禍，致使新購之重機毀損，問：
甲能否向A保險公司就此事件請求保險金之給付？A保險公司得否以甲
尚未繳交保險費及未有保險契約書面之簽訂為由，拒付保險金？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "2964ccdcbdb9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0808", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00213', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '甲列乙及丙二人為被告，於111年 12 月 1日起訴，聲明求為判命乙及丙
應將 A地所有權移轉登記予甲，甲陳述之事實及理由為：乙、丙、丁三
人各以應有部分3 分之 1共有 A地，甲於 111 年 10 月 5 日以新臺幣 500
萬元向乙及丙購買該地，因乙、丙未依約辦理過戶，基於買賣標的物移
轉請求權提起本訴。
在言詞辯論時，乙抗辯甲未併列丁為共同被告，本訴欠缺當事人適格。
法院應如何處理？（20 分）
法院就本訴所為本案確定判決之效力是否及於丁？（15分）
丁主張其優先購買權時，對於乙、丙所受之本案確定終局判決，得否
提起第三人撤銷之訴？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "e882adf48397", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0811", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00214', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '甲涉犯妨礙名譽罪嫌，被害人乙於 106 年 9 月 14 日向檢察官申告犯罪
事實，並請求追訴，經檢察官 A偵查後，同年 10月 11 日向管轄法院聲
請簡易判決處刑，於同年 10 月 16 日公告，同年 11 月 6 日繫屬於管轄
法院，經該法院審理後於同年 11月 13 日處罰金新臺幣 3 千元，如易服
勞役，以新臺幣 1 千元折算 1 日。惟乙就同一事實，於同年 9 月 14 日
於警察局製作筆錄時，亦提出告訴，該警察局同月 27 日移送偵辦，檢察
署於同年10 月 18 日分案由 B檢察官偵辦，乙於同年 11月 7 日向 B檢
察官提出「聲請撤回告訴狀」，B檢察官則將該撤回告訴狀附於卷內，並
於同月 10日就本案為不起訴處分。試論管轄法院對甲為處罰金新臺幣 3
千元之簡易判決是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "e882adf48397", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0811", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00215', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '甲涉犯槍砲彈藥刀械管制條例罪嫌，警察丙、丁二人持檢察官簽發之拘
票，至甲宅進行拘提，於途中發現甲與友人乙正在散步，立即出示拘票
拘提甲，並向甲云：「現在要搜索你隨身攜帶之背包，你是否同意？」，
甲聞言後同意之。丙、丁二人立即搜索甲所隨身攜帶之背包查獲槍彈等
物並扣押後，強迫甲於搜索之筆錄上簽名。經檢察官向管轄法院提起公
訴，審理期間辯護人 A主張，警察丙、丁二人雖有得到甲之同意搜索其
背包，但於搜索前未出示證件，且搜索後強迫其在同意搜索之筆錄簽名，
未踐行自願性同意搜索之合法程序，為非法搜索，自不能以扣案槍彈為
本案之證據。試論辯護人之主張是否有理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "e882adf48397", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0811", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
